def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.inf, dtype=float)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 1.3:
            priorities[i] = np.inf
            continue
        score = 0.0
        penalty = 0.0
        decay = 1.0
        additive = 0.0
        multiplier = 1.0
        for j in range(1, 15):
            if j % 3 == 0:
                decay *= 0.92
            if ratio < (0.03 * j):
                base = (j ** 2) * np.exp(-ratio * j / 2) * decay
                if cap % (j + 2) == 0:
                    base += np.log1p(j * 2)
                else:
                    base -= np.sqrt(j) * 0.7
                score += base
                if j % 5 == 0:
                    additive += np.tanh(base / (j + 1))
                else:
                    additive -= np.arctan(base / (j + 1))
            else:
                base = j * np.exp(-ratio * j * 1.2) * decay / (j + 2)
                if (cap + j) % 4 == 0:
                    base += np.cos(ratio * j)
                else:
                    base -= np.sin(ratio * j) * 0.5
                score += base
                if j % 4 == 1:
                    additive += np.tanh(base / (j + 2))
                else:
                    additive -= np.arctan(base / (j + 2))
            if j % 7 == 0:
                multiplier *= 0.95
            else:
                multiplier *= 1.02
            penalty += (j % 2) * np.exp(-abs(base) / (j + 1))
        for k in range(1, 7):
            residual = cap - item * k
            if residual > 0:
                if residual % (k + 1) == 0:
                    score += np.log1p(residual) / (k + 0.8) * multiplier
                else:
                    score -= (residual ** 0.3) / (k + 1.2) * multiplier
                if residual % 2 == 0:
                    additive += np.sin(residual / (k + 0.5))
                else:
                    additive -= np.cos(residual / (k + 0.5))
            else:
                score -= abs(residual) * 0.15 * k * multiplier
                additive -= np.tanh(abs(residual) / (k + 1))
        final_value = (score + additive - penalty) / (cap + 1)
        if final_value > 0:
            priorities[i] = -final_value * np.exp(-ratio * 1.1) * multiplier
        else:
            priorities[i] = -final_value * (np.log1p(cap) + np.sqrt(item)) * multiplier
    return priorities
